{
    "level": "A1",
    "intro": "W tym temacie nauczysz się wybierać między <strong>this, that, these, those</strong> na podstawie <strong>blisko / daleko</strong> oraz <strong>liczby pojedynczej / mnogiej</strong>.",
    "rules": [
        {
            "label": "BLISKO + LICZBA POJEDYNCZA",
            "color": "emerald",
            "text": "<strong>This</strong> odnosi się do jednej rzeczy blisko mówiącego:",
            "example": "This book is mine."
        },
        {
            "label": "DALEKO + LICZBA POJEDYNCZA",
            "color": "blue",
            "text": "<strong>That</strong> odnosi się do jednej rzeczy dalej od mówiącego:",
            "example": "That car is expensive."
        },
        {
            "label": "LICZBA MNOGA",
            "color": "amber",
            "text": "<strong>These / those</strong> to formy liczby mnogiej: blisko albo daleko.",
            "example": "These shoes are new. / Those houses are old."
        }
    ]
}

{
    "title": "1. Szybki schemat",
    "intro": "Połącz odległość i liczbę, aby od razu wybrać poprawny zaimek wskazujący.",
    "items": [
        {
            "label": "Blisko + liczba pojedyncza",
            "title": "this",
            "subtitle": "this bag, this idea, this one"
        },
        {
            "label": "Daleko + liczba pojedyncza",
            "title": "that",
            "subtitle": "that bag, that idea, that one"
        },
        {
            "label": "Blisko + liczba mnoga",
            "title": "these",
            "subtitle": "these bags, these ideas, these ones"
        },
        {
            "label": "Daleko + liczba mnoga",
            "title": "those",
            "subtitle": "those bags, those ideas, those ones"
        }
    ]
}

{
    "title": "2. Główne użycia",
    "sections": [
        {
            "label": "Blisko czy daleko",
            "color": "emerald",
            "description": "Zaimek wskazujący często pokazuje, <strong>gdzie</strong> znajduje się rzecz albo idea względem mówiącego.",
            "examples": [
                {
                    "en": "This chair is comfortable.",
                    "ua": "To krzesło jest wygodne."
                },
                {
                    "en": "That building is very old.",
                    "ua": "Tamten budynek jest bardzo stary."
                },
                {
                    "en": "Those lights look beautiful at night.",
                    "ua": "Tamte światła pięknie wyglądają nocą."
                }
            ]
        },
        {
            "label": "Liczba pojedyncza i mnoga",
            "color": "blue",
            "description": "Forma zależy jednocześnie od odległości i od liczby.",
            "examples": [
                {
                    "en": "This apple is sweet, but these apples are sour.",
                    "ua": "To jabłko jest słodkie, ale te jabłka są kwaśne."
                },
                {
                    "en": "That photo is blurry, and those photos are darker.",
                    "ua": "Tamto zdjęcie jest niewyraźne, a tamte zdjęcia są ciemniejsze."
                },
                {
                    "en": "Who is that? Who are those people?",
                    "ua": "Kto to jest? Kim są tamci ludzie?"
                }
            ]
        },
        {
            "label": "Typowe wzory",
            "color": "amber",
            "description": "Po demonstrative często stoi <strong>rzeczownik</strong>, ale słowo może też występować samodzielnie.",
            "examples": [
                {
                    "en": "This book is easier than that one.",
                    "ua": "Ta książka jest łatwiejsza niż tamta."
                },
                {
                    "en": "These are my keys.",
                    "ua": "To są moje klucze."
                },
                {
                    "en": "I do not like those.",
                    "ua": "Nie lubię tamtych."
                }
            ],
            "note": "This / that łączą się z liczbą pojedynczą, a these / those z mnogą."
        }
    ]
}

{
    "title": "3. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "This z rzeczownikiem w liczbie mnogiej.",
            "wrong": "This shoes are new.",
            "right": "✅ <span class=\"font-mono\">These shoes are new.</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Złe połączenie that / those z czasownikiem.",
            "wrong": "That are my keys.",
            "right": "✅ <span class=\"font-mono\">Those are my keys.</span> / <span class=\"font-mono\">That is my key.</span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Mylenie one i ones.",
            "wrong": "I like this ones.",
            "right": "✅ <span class=\"font-mono\">I like these ones.</span> / <span class=\"font-mono\">I like this one.</span>"
        }
    ]
}

{
    "title": "4. Krótkie podsumowanie",
    "items": [
        "<strong>This</strong> = blisko + liczba pojedyncza.",
        "<strong>That</strong> = daleko + liczba pojedyncza.",
        "<strong>These</strong> = blisko + liczba mnoga.",
        "<strong>Those</strong> = daleko + liczba mnoga.",
        "Demonstrative może stać przed rzeczownikiem albo samodzielnie: <em>this book</em>, <em>those</em>."
    ]
}

